1	/**
2	 * WebSocket protocol frame types — authoritative TypeScript definitions.
3	 *
4	 * Source: docs/design/protocol-websocket.md §8 (type block) and §2 (payload
5	 * shapes). These types are consumed by ws.ts (server-side handler) and will
6	 * also be re-exported for the future Dashboard client.
7	 *
8	 * Conventions:
9	 *  - ServerFrame: server → client envelope with v:1, type, seq, ts, payload.
10	 *  - ClientFrame: client → server envelope with v:1, type, id, payload.
11	 *  - seq rules: per-session monotonic starting at 1; non-session frames seq:0;
12	 *    backfill replays preserve original seq.
13	 */
14	
15	// ---------------------------------------------------------------------------
16	// Envelope types (§8)
17	// ---------------------------------------------------------------------------
18	
19	export type ServerFrameType =
20	  | 'hello'
21	  | 'workflow.snapshot'
22	  | 'workflow.update'
23	  | 'workflow.index.update'
24	  | 'item.state'
25	  | 'item.data'
26	  | 'stage.started'
27	  | 'stage.complete'
28	  | 'session.started'
29	  | 'session.ended'
30	  | 'stream.text'
31	  | 'stream.thinking'
32	  | 'stream.tool_use'
33	  | 'stream.tool_result'
34	  | 'stream.usage'
35	  | 'stream.system_notice'
36	  | 'prepost.command.started'
37	  | 'prepost.command.output'
38	  | 'prepost.command.ended'
39	  | 'notice'
40	  | 'error'
41	  | 'pong'
42	  | 'backfill.truncated';
43	
44	export type ClientFrameType =
45	  | 'subscribe'
46	  | 'unsubscribe'
47	  | 'control'
48	  | 'ack'
49	  | 'ping';
50	
51	export interface ServerFrame<T = unknown> {
52	  v: 1;
53	  type: ServerFrameType;
54	  /** Absent on hello, pong, notice (global frames). */
55	  workflowId?: string;
56	  /** Absent on workflow-scope frames. */
57	  sessionId?: string;
58	  /** Monotonic per session (starts at 1). Non-session frames: 0. */
59	  seq: number;
60	  ts: string;
61	  payload: T;
62	}
63	
64	export interface ClientFrame<T = unknown> {
65	  v: 1;
66	  type: ClientFrameType;
67	  /** Client-generated commandId (uuid); idempotency key. */
68	  id: string;
69	  payload: T;
70	}
71	
72	// ---------------------------------------------------------------------------
73	// Server frame payload types (§2)
74	// ---------------------------------------------------------------------------
75	
76	/** §2.1 — sent once on connect before any other frame. */
77	export interface HelloPayload {
78	  serverVersion: string;
79	  protocolVersion: 1;
80	  capabilities: string[];
81	  heartbeatIntervalMs: number;
82	}
83	
84	/** §2.2 — full workflow state dump, sent in response to subscribe. */
85	export interface WorkflowSnapshotPayload {
86	  workflow: {
87	    id: string;
88	    name: string;
89	    status: string;
90	    currentStage: string | null;
91	    createdAt: string;
92	    recoveryState?: unknown | null;
93	    githubState?: unknown | null;
94	  };
95	  stages: StageProjection[];
96	  items: ItemProjection[];
97	  activeSessions: SessionProjection[];
98	  pendingAttention: PendingAttentionEntry[];
99	}
100	
101	export interface StageProjection {
102	  id: string;
103	  run: 'once' | 'per-item';
104	  phases: string[];
105	  status: 'pending' | 'in_progress' | 'complete' | 'blocked';
106	  needsApproval: boolean;
107	}
108	
109	export interface ItemProjection {
110	  id: string;
111	  stageId: string;
112	  state: ItemStateProjection;
113	  displayTitle: string | null;
114	  displaySubtitle: string | null;
115	}
116	
117	export interface ItemStateProjection {
118	  status: string;
119	  currentPhase: string | null;
120	  retryCount: number;
121	  blockedReason: string | null;
122	}
123	
124	export interface SessionProjection {
125	  sessionId: string;
126	  phase: string;
127	  attempt: number;
128	  startedAt: string;
129	  parentSessionId?: string | null;
130	}
131	
132	export interface PendingAttentionEntry {
133	  id: number;
134	  kind: string;
135	  payload: unknown;
136	  createdAt: string;
137	}
138	
139	/** §2.3 — item.state partial update. */
140	export interface ItemStatePayload {
141	  itemId: string;
142	  stageId: string;
143	  state: Partial<ItemStateProjection>;
144	}
145	
146	/** §2.3 — item.data on-demand blob. */
147	export interface ItemDataPayload {
148	  itemId: string;
149	  data: unknown;
150	}
151	
152	/** §2.3a */
153	export interface StageStartedPayload {
154	  stageId: string;
155	  run: 'once' | 'per-item';
156	  itemCount?: number;
157	}
158	
159	export interface StageCompletePayload {
160	  stageId: string;
161	  nextStageId: string | null;
162	  needsApproval: boolean;
163	  itemSummary?: {
164	    complete: number;
165	    blocked: number;
166	    abandoned: number;
167	  };
168	}
169	
170	/** §2.5 */
171	export interface SessionStartedPayload {
172	  sessionId: string;
173	  phase: string;
174	  attempt: number;
175	  startedAt: string;
176	  parentSessionId?: string | null;
177	}
178	
179	export interface SessionEndedPayload {
180	  sessionId: string;
181	  endedAt: string;
182	  exitCode: number | null;
183	  statusFlags: Record<string, number | boolean>;
184	  reason: 'ok' | 'fail' | 'cancelled' | 'rate_limited' | 'tainted';
185	}
186	
187	/** §2.8 */
188	export interface ErrorPayload {
189	  code: string;
190	  message: string;
191	  commandId?: string;
192	}
193	
194	export interface NoticePayload {
195	  severity: 'info' | 'requires_attention';
196	  kind: string;
197	  message: string;
198	  persistedAttentionId?: number;
199	}
200	
201	/** §2.10 */
202	export interface BackfillTruncatedPayload {
203	  workflowId: string;
204	  sinceSeq: number;
205	  minAvailableSeq: number;
206	  /** URL to page the full log via HTTP GET /api/sessions/:id/log. */
207	  httpFetchUrl: string;
208	}
209	
210	// ---------------------------------------------------------------------------
211	// Client frame payload types (§3)
212	// ---------------------------------------------------------------------------
213	
214	export interface SubscribePayload {
215	  workflowId: string;
216	  sinceSeq?: number;
217	}
218	
219	export interface UnsubscribePayload {
220	  workflowId: string;
221	}
222	
223	export type ControlAction =
224	  | 'pause'
225	  | 'resume'
226	  | 'cancel'
227	  | 'skip'
228	  | 'rerun-phase'
229	  | 'inject-context'
230	  | 'unblock'
231	  | 'retry'
232	  | 'approve-stage';
233	
234	export interface ControlPayload {
235	  workflowId: string;
236	  action: ControlAction;
237	  itemId?: string;
238	  stageId?: string;
239	  extra?: unknown;
240	}
241	
242	export interface AckPayload {
243	  lastAppliedSeq: number;
244	  sessionId: string;
245	}
246	
247	export interface PingPayload {
248	  clientTs: string;
249	}
250	
251	// ---------------------------------------------------------------------------
252	// Helpers
253	// ---------------------------------------------------------------------------
254	
255	/**
256	 * Build a non-session ServerFrame (seq:0, no workflowId/sessionId unless
257	 * explicitly provided in opts).
258	 */
259	export function makeFrame<T>(
260	  type: ServerFrameType,
261	  payload: T,
262	  opts: { workflowId?: string; sessionId?: string; seq?: number } = {},
263	): ServerFrame<T> {
264	  return {
265	    v: 1,
266	    type,
267	    workflowId: opts.workflowId,
268	    sessionId: opts.sessionId,
269	    seq: opts.seq ?? 0,
270	    ts: new Date().toISOString(),
271	    payload,
272	  };
273	}
274	
275	/** Build an error frame (seq:0, no workflowId/sessionId). */
276	export function makeErrorFrame(
277	  code: string,
278	  message: string,
279	  commandId?: string,
280	): ServerFrame<ErrorPayload> {
281	  return makeFrame('error', { code, message, ...(commandId ? { commandId } : {}) });
282	}
