1	/**
2	 * Yoke Fastify HTTP + WebSocket server.
3	 *
4	 * This module replaces the interim Node.js http.Server in http.ts.  It
5	 * implements:
6	 *   - All HTTP companion endpoints from protocol-websocket.md §7.
7	 *   - WebSocket route at /stream (protocol per ws.ts).
8	 *   - Exclusive 127.0.0.1 binding (D57, RC: no 0.0.0.0 code path).
9	 *
10	 * Design invariants:
11	 *   - All reads use db.reader() (read-only connection).
12	 *   - The only SQLite write in this module is attention ack (sets
13	 *     acknowledged_at on pending_attention rows); all workflow/item state
14	 *     transitions are the pipeline engine's domain.
15	 *   - No authentication middleware (D57).
16	 *   - No 0.0.0.0 bind path exists anywhere in this file.
17	 */
18	
19	import Fastify, { type FastifyInstance, type FastifyRequest, type FastifyReply } from 'fastify';
20	import fastifyWebsocket, { type SocketStream } from '@fastify/websocket';
21	import type { DbPool } from '../storage/db.js';
22	import { readLogPage } from '../session-log/reader.js';
23	import {
24	  SessionSeqStore,
25	  BackfillBuffer,
26	  createWsHandler,
27	} from './ws.js';
28	import { IdempotencyStore } from './idempotency.js';
29	
30	// ---------------------------------------------------------------------------
31	// Internal helpers
32	// ---------------------------------------------------------------------------
33	
34	function badRequest(reply: FastifyReply, message: string): FastifyReply {
35	  return reply.status(400).send({ error: message });
36	}
37	
38	function notFound(reply: FastifyReply, message = 'not found'): FastifyReply {
39	  return reply.status(404).send({ error: message });
40	}
41	
42	// ---------------------------------------------------------------------------
43	// Snapshot helpers
44	// ---------------------------------------------------------------------------
45	
46	interface WorkflowRow {
47	  id: string;
48	  name: string;
49	  status: string;
50	  current_stage: string | null;
51	  created_at: string;
52	  updated_at: string;
53	}
54	
55	// ---------------------------------------------------------------------------
56	// Server factory
57	// ---------------------------------------------------------------------------
58	
59	export interface ServerOptions {
60	  /**
61	   * Bind host — MUST be '127.0.0.1'. Passing any other value throws at
62	   * listen time. Default: '127.0.0.1'.
63	   */
64	  host?: '127.0.0.1';
65	  /** Server port. 0 = OS-assigned (default for tests). */
66	  port?: number;
67	}
68	
69	/** Shared in-memory state for the WS layer — exposed so tests and the pipeline engine integration can push frames. */
70	export interface ServerState {
71	  seqStore: SessionSeqStore;
72	  backfillBuffer: BackfillBuffer;
73	  idempotency: IdempotencyStore;
74	}
75	
76	export interface ServerHandle {
77	  fastify: FastifyInstance;
78	  state: ServerState;
79	}
80	
81	/**
82	 * Creates and configures the Fastify server.
83	 *
84	 * Callers must await fastify.listen(...) to start accepting connections.
85	 * The returned instance's .server.address() gives the bound port.
86	 *
87	 * @param db  DbPool opened by the caller.
88	 */
89	export async function createServer(db: DbPool): Promise<ServerHandle> {
90	  const fastify = Fastify({ logger: false });
91	
92	  // Shared state for the WS layer.
93	  const seqStore = new SessionSeqStore();
94	  const backfillBuffer = new BackfillBuffer();
95	  const idempotency = new IdempotencyStore();
96	
97	  // Register WebSocket plugin.
98	  await fastify.register(fastifyWebsocket);
99	
100	  // WebSocket route at /stream (§4 Lifecycle).
101	  // Registered directly on the root fastify instance so it inherits the
102	  // @fastify/websocket plugin decoration without sub-plugin scoping issues.
103	  const wsHandler = createWsHandler({ db, idempotency, seqStore, backfillBuffer });
104	  fastify.get('/stream', { websocket: true }, (connection: SocketStream) => {
105	    wsHandler(connection.socket);
106	  });
107	
108	  // -------------------------------------------------------------------------
109	  // §7 HTTP companion endpoints
110	  // All read from db.reader() — no workflow/item state writes.
111	  // -------------------------------------------------------------------------
112	
113	  // GET /api/workflows?status=&q=&before=&limit=
114	  // Keyset pagination (D47). Ordered by created_at DESC.
115	  fastify.get(
116	    '/api/workflows',
117	    async (req: FastifyRequest, reply: FastifyReply) => {
118	      const qs = req.query as Record<string, string | undefined>;
119	      const limitRaw = parseInt(qs.limit ?? '20', 10);
120	      if (!isFinite(limitRaw) || limitRaw < 1) return badRequest(reply, 'limit must be a positive integer');
121	      const limit = Math.min(limitRaw, 100);
122	
123	      let sql = 'SELECT id, name, status, current_stage, created_at, updated_at FROM workflows WHERE 1=1';
124	      const params: unknown[] = [];
125	
126	      if (qs.status) {
127	        sql += ' AND status = ?';
128	        params.push(qs.status);
129	      }
130	      if (qs.q) {
131	        sql += ' AND name LIKE ?';
132	        params.push(`%${qs.q}%`);
133	      }
134	      if (qs.before) {
135	        sql += ' AND created_at < ?';
136	        params.push(qs.before);
137	      }
138	      sql += ` ORDER BY created_at DESC LIMIT ${limit + 1}`;
139	
140	      const rows = db.reader().prepare(sql).all(...params) as WorkflowRow[];
141	      const hasMore = rows.length > limit;
142	      const workflows = hasMore ? rows.slice(0, limit) : rows;
143	
144	      return reply.send({
145	        workflows,
146	        hasMore,
147	        nextBefore: hasMore ? workflows[workflows.length - 1].created_at : null,
148	      });
149	    },
150	  );
151	
152	  // GET /api/workflows/:id/timeline
153	  // Merged SQLite events + JSONL (§Obs, D34).
154	  fastify.get(
155	    '/api/workflows/:id/timeline',
156	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
157	      const { id } = req.params;
158	      const reader = db.reader();
159	
160	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
161	      if (!wf) return notFound(reply, 'workflow not found');
162	
163	      const events = reader
164	        .prepare(
165	          'SELECT id, ts, workflow_id, item_id, session_id, stage, phase, attempt, event_type, level, message, extra FROM events WHERE workflow_id = ? ORDER BY ts, id',
166	        )
167	        .all(id) as Array<{
168	          id: number;
169	          ts: string;
170	          workflow_id: string;
171	          item_id: string | null;
172	          session_id: string | null;
173	          stage: string | null;
174	          phase: string | null;
175	          attempt: number | null;
176	          event_type: string;
177	          level: string;
178	          message: string;
179	          extra: string | null;
180	        }>;
181	
182	      return reply.send({
183	        workflowId: id,
184	        events: events.map((e) => ({
185	          ...e,
186	          extra: e.extra ? (() => { try { return JSON.parse(e.extra!); } catch { return e.extra; } })() : null,
187	        })),
188	      });
189	    },
190	  );
191	
192	  // GET /api/sessions/:id/log?sinceSeq=&limit=
193	  // Paged stream-json fetch (D48a). Reads from JSONL file via readLogPage.
194	  fastify.get(
195	    '/api/sessions/:id/log',
196	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
197	      const { id } = req.params;
198	      const qs = req.query as Record<string, string | undefined>;
199	
200	      const sinceSeqRaw = qs.sinceSeq !== undefined ? parseInt(qs.sinceSeq, 10) : 0;
201	      const limitRaw = qs.limit !== undefined ? parseInt(qs.limit, 10) : 100;
202	
203	      if (!isFinite(sinceSeqRaw) || sinceSeqRaw < 0) return badRequest(reply, 'sinceSeq must be a non-negative integer');
204	      if (!isFinite(limitRaw) || limitRaw < 1) return badRequest(reply, 'limit must be a positive integer');
205	
206	      const sinceSeq = Math.max(0, sinceSeqRaw);
207	      const limit = Math.max(1, limitRaw);
208	
209	      const reader = db.reader();
210	      const row = reader
211	        .prepare('SELECT session_log_path FROM sessions WHERE id = ?')
212	        .get(id) as { session_log_path: string | null } | undefined;
213	
214	      if (!row) return notFound(reply, 'session not found');
215	
216	      if (!row.session_log_path) {
217	        return reply.send({ entries: [], nextSeq: sinceSeq, hasMore: false });
218	      }
219	
220	      const page = await readLogPage(row.session_log_path, sinceSeq, limit);
221	      if (!page) {
222	        return reply.send({ entries: [], nextSeq: sinceSeq, hasMore: false });
223	      }
224	
225	      return reply.send(page);
226	    },
227	  );
228	
229	  // GET /api/workflows/:id/usage?groupBy=feature|phase|profile|session
230	  // Token aggregates per groupBy dimension.
231	  fastify.get(
232	    '/api/workflows/:id/usage',
233	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
234	      const { id } = req.params;
235	      const qs = req.query as Record<string, string | undefined>;
236	      const groupBy = qs.groupBy ?? 'session';
237	
238	      const validGroupBy = ['feature', 'phase', 'profile', 'session'];
239	      if (!validGroupBy.includes(groupBy)) {
240	        return badRequest(reply, `groupBy must be one of: ${validGroupBy.join(', ')}`);
241	      }
242	
243	      const reader = db.reader();
244	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
245	      if (!wf) return notFound(reply, 'workflow not found');
246	
247	      // Map groupBy dimension to SQLite column.
248	      const groupCol: Record<string, string> = {
249	        feature: 'item_id',
250	        phase: 'phase',
251	        profile: 'agent_profile',
252	        session: 'id',
253	      };
254	      const col = groupCol[groupBy];
255	
256	      const rows = reader
257	        .prepare(
258	          `SELECT ${col} AS dimension,
259	                  SUM(input_tokens) AS input_tokens,
260	                  SUM(output_tokens) AS output_tokens,
261	                  SUM(cache_creation_input_tokens) AS cache_creation_input_tokens,
262	                  SUM(cache_read_input_tokens) AS cache_read_input_tokens,
263	                  COUNT(*) AS session_count
264	           FROM sessions
265	           WHERE workflow_id = ?
266	           GROUP BY ${col}
267	           ORDER BY input_tokens DESC`,
268	        )
269	        .all(id);
270	
271	      return reply.send({ workflowId: id, groupBy, rows });
272	    },
273	  );
274	
275	  // GET /api/workflows/:id/usage/timeseries?bucket=hour|day
276	  // Usage timeseries bucketed by hour or day.
277	  fastify.get(
278	    '/api/workflows/:id/usage/timeseries',
279	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
280	      const { id } = req.params;
281	      const qs = req.query as Record<string, string | undefined>;
282	      const bucket = qs.bucket ?? 'hour';
283	
284	      if (bucket !== 'hour' && bucket !== 'day') {
285	        return badRequest(reply, 'bucket must be hour or day');
286	      }
287	
288	      const reader = db.reader();
289	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
290	      if (!wf) return notFound(reply, 'workflow not found');
291	
292	      // SQLite strftime format for the requested bucket.
293	      const fmt = bucket === 'hour' ? '%Y-%m-%dT%H:00:00Z' : '%Y-%m-%dT00:00:00Z';
294	
295	      const rows = reader
296	        .prepare(
297	          `SELECT strftime('${fmt}', started_at) AS bucket,
298	                  SUM(input_tokens) AS input_tokens,
299	                  SUM(output_tokens) AS output_tokens,
300	                  SUM(cache_creation_input_tokens) AS cache_creation_input_tokens,
301	                  SUM(cache_read_input_tokens) AS cache_read_input_tokens,
302	                  COUNT(*) AS session_count
303	           FROM sessions
304	           WHERE workflow_id = ?
305	           GROUP BY bucket
306	           ORDER BY bucket ASC`,
307	        )
308	        .all(id);
309	
310	      return reply.send({ workflowId: id, bucket, rows });
311	    },
312	  );
313	
314	  // POST /api/workflows/:id/control
315	  // Idempotent manual control (mirrors WS control frame).
316	  fastify.post(
317	    '/api/workflows/:id/control',
318	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
319	      const { id } = req.params;
320	      const body = req.body as {
321	        commandId?: string;
322	        action?: string;
323	        itemId?: string;
324	        stageId?: string;
325	        extra?: unknown;
326	      } | null;
327	
328	      if (!body?.commandId) return badRequest(reply, 'commandId is required');
329	      if (!body.action) return badRequest(reply, 'action is required');
330	
331	      const reader = db.reader();
332	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
333	      if (!wf) return notFound(reply, 'workflow not found');
334	
335	      // Idempotency check (AC-4, RC: not by re-executing).
336	      const cached = idempotency.get(body.commandId);
337	      if (cached !== undefined) {
338	        return reply.status(200).send(cached);
339	      }
340	
341	      // Cache and return accepted response. Actual execution deferred to pipeline engine.
342	      const response = {
343	        status: 'accepted',
344	        commandId: body.commandId,
345	        workflowId: id,
346	        action: body.action,
347	      };
348	      idempotency.set(body.commandId, response);
349	
350	      return reply.status(202).send(response);
351	    },
352	  );
353	
354	  // POST /api/workflows/:id/attention/:attentionId/ack
355	  // Clear a pending attention item.
356	  fastify.post(
357	    '/api/workflows/:id/attention/:attentionId/ack',
358	    async (
359	      req: FastifyRequest<{ Params: { id: string; attentionId: string } }>,
360	      reply: FastifyReply,
361	    ) => {
362	      const { id, attentionId } = req.params;
363	      const attId = parseInt(attentionId, 10);
364	      if (!isFinite(attId)) return badRequest(reply, 'attentionId must be an integer');
365	
366	      const reader = db.reader();
367	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
368	      if (!wf) return notFound(reply, 'workflow not found');
369	
370	      const row = reader
371	        .prepare('SELECT id, acknowledged_at FROM pending_attention WHERE id = ? AND workflow_id = ?')
372	        .get(attId, id) as { id: number; acknowledged_at: string | null } | undefined;
373	
374	      if (!row) return notFound(reply, 'attention item not found');
375	
376	      // Already acknowledged — idempotent.
377	      if (row.acknowledged_at) {
378	        return reply.send({ status: 'already_acknowledged', id: attId });
379	      }
380	
381	      // This is the one write from the API layer: acknowledging a pending
382	      // attention item is an operational action, not a state-machine transition.
383	      db.writer
384	        .prepare(
385	          "UPDATE pending_attention SET acknowledged_at = datetime('now') WHERE id = ?",
386	        )
387	        .run(attId);
388	
389	      return reply.send({ status: 'acknowledged', id: attId });
390	    },
391	  );
392	
393	  return { fastify, state: { seqStore, backfillBuffer, idempotency } };
394	}
