1	/**
2	 * WebSocket protocol frame types — authoritative TypeScript definitions.
3	 *
4	 * Source: docs/design/protocol-websocket.md §8 (type block) and §2 (payload
5	 * shapes). These types are consumed by ws.ts (server-side handler) and will
6	 * also be re-exported for the future Dashboard client.
7	 *
8	 * Conventions:
9	 *  - ServerFrame: server → client envelope with v:1, type, seq, ts, payload.
10	 *  - ClientFrame: client → server envelope with v:1, type, id, payload.
11	 *  - seq rules: per-session monotonic starting at 1; non-session frames seq:0;
12	 *    backfill replays preserve original seq.
13	 */
14	
15	// ---------------------------------------------------------------------------
16	// Envelope types (§8)
17	// ---------------------------------------------------------------------------
18	
19	export type ServerFrameType =
20	  | 'hello'
21	  | 'workflow.snapshot'
22	  | 'workflow.update'
23	  | 'workflow.index.update'
24	  | 'item.state'
25	  | 'item.data'
26	  | 'stage.started'
27	  | 'stage.complete'
28	  | 'session.started'
29	  | 'session.ended'
30	  | 'stream.text'
31	  | 'stream.thinking'
32	  | 'stream.tool_use'
33	  | 'stream.tool_result'
34	  | 'stream.usage'
35	  | 'stream.system_notice'
36	  | 'prepost.command.started'
37	  | 'prepost.command.output'
38	  | 'prepost.command.ended'
39	  | 'notice'
40	  | 'error'
41	  | 'pong'
42	  | 'backfill.truncated';
43	
44	export type ClientFrameType =
45	  | 'subscribe'
46	  | 'unsubscribe'
47	  | 'control'
48	  | 'ack'
49	  | 'ping';
50	
51	export interface ServerFrame<T = unknown> {
52	  v: 1;
53	  type: ServerFrameType;
54	  /** Absent on hello, pong, notice (global frames). */
55	  workflowId?: string;
56	  /** Absent on workflow-scope frames. */
57	  sessionId?: string;
58	  /** Monotonic per session (starts at 1). Non-session frames: 0. */
59	  seq: number;
60	  ts: string;
61	  payload: T;
62	}
63	
64	export interface ClientFrame<T = unknown> {
65	  v: 1;
66	  type: ClientFrameType;
67	  /** Client-generated commandId (uuid); idempotency key. */
68	  id: string;
69	  payload: T;
70	}
71	
