1	/**
2	 * WebSocket connection handler.
3	 *
4	 * Implements the protocol defined in docs/design/protocol-websocket.md.
5	 *
6	 * Responsibilities:
7	 *  - Send hello frame immediately on connect (AC-1).
8	 *  - Validate ClientFrame.v; close 4001 on mismatch (AC-1).
9	 *  - Route subscribe / unsubscribe / control / ack / ping frames.
10	 *  - Enforce subscription cap (4 per client); send error + close 4002 on
11	 *    the 5th subscribe (AC-3).
12	 *  - For subscribe: send workflow.snapshot then backfill frames (or
13	 *    backfill.truncated if sinceSeq is too old) (AC-2).
14	 *  - Per-session monotonic seq starting at 1; non-session frames seq:0;
15	 *    backfill replays preserve original seq (RC: seq rules).
16	 *  - control commandId idempotency: cached response within 5 min (AC-4).
17	 *
18	 * Non-responsibilities (deferred to pipeline engine integration):
19	 *  - Pushing live frames to connected clients — the pipeline engine will call
20	 *    SessionSeqStore.next() + BackfillBuffer.push() + broadcast().
21	 *  - Validating / executing control actions beyond recording + caching.
22	 */
23	
24	import type { WebSocket } from 'ws';
25	import type { DbPool } from '../storage/db.js';
26	import type {
27	  ClientFrame,
28	  SubscribePayload,
29	  UnsubscribePayload,
30	  ControlPayload,
31	  AckPayload,
32	  PingPayload,
33	  ServerFrame,
34	  WorkflowSnapshotPayload,
35	  StageProjection,
36	  ItemProjection,
37	  SessionProjection,
38	  PendingAttentionEntry,
39	} from './frames.js';
40	import { makeFrame, makeErrorFrame } from './frames.js';
41	import type { IdempotencyStore } from './idempotency.js';
42	
43	// ---------------------------------------------------------------------------
44	// Constants
45	// ---------------------------------------------------------------------------
46	
47	const PROTOCOL_VERSION = 1;
48	const MAX_SUBSCRIPTIONS = 4;
49	const SERVER_VERSION = '0.0.1';
50	const HEARTBEAT_INTERVAL_MS = 30_000;
51	const CAPABILITIES: string[] = ['backfill', 'keepalive', 'prepost'];
52	
53	/** Max frames retained per session for WS backfill replay. */
54	export const MAX_BACKFILL_BUFFER = 500;
55	
56	// ---------------------------------------------------------------------------
57	// SessionSeqStore — monotonic seq per sessionId
58	// ---------------------------------------------------------------------------
59	
60	/**
61	 * Tracks the current seq number for each active session.
62	 * Shared across all WS connections (frames from the pipeline engine are
63	 * stamped with the next seq and then broadcast to all subscribed clients).
64	 */
65	export class SessionSeqStore {
66	  private readonly seqs = new Map<string, number>();
67	
68	  /** Increments and returns the next seq for sessionId (starts at 1). */
69	  next(sessionId: string): number {
70	    const seq = (this.seqs.get(sessionId) ?? 0) + 1;
71	    this.seqs.set(sessionId, seq);
72	    return seq;
73	  }
74	
75	  /** Returns the current (last issued) seq for sessionId, or 0 if none. */
76	  current(sessionId: string): number {
77	    return this.seqs.get(sessionId) ?? 0;
78	  }
79	}
80	
81	// ---------------------------------------------------------------------------
82	// BackfillBuffer — per-session in-memory frame ring buffer
83	// ---------------------------------------------------------------------------
84	
85	/**
86	 * Retains the last MAX_BACKFILL_BUFFER frames per session for WS backfill
87	 * replay. When a client reconnects with sinceSeq:
88	 *   - If sinceSeq >= earliestRetained − 1: replay frames with seq > sinceSeq.
89	 *   - Else: caller should emit backfill.truncated and point to HTTP endpoint.
90	 */
91	export class BackfillBuffer {
92	  private readonly buffers = new Map<string, ServerFrame[]>();
93	
94	  /**
95	   * Appends frame to the session's ring buffer, evicting the oldest entry
96	   * if the buffer exceeds MAX_BACKFILL_BUFFER.
97	   */
98	  push(sessionId: string, frame: ServerFrame): void {
99	    let buf = this.buffers.get(sessionId);
100	    if (!buf) {
101	      buf = [];
102	      this.buffers.set(sessionId, buf);
103	    }
104	    buf.push(frame);
105	    if (buf.length > MAX_BACKFILL_BUFFER) {
106	      buf.shift();
107	    }
108	  }
109	
110	  /**
111	   * Returns frames for sessionId with seq > sinceSeq, or null if sinceSeq
112	   * predates the earliest retained frame (caller should emit
113	   * backfill.truncated). Returns [] if no frames exist yet.
114	   */
115	  getFramesSince(sessionId: string, sinceSeq: number): ServerFrame[] | null {
116	    const buf = this.buffers.get(sessionId);
117	    if (!buf || buf.length === 0) return [];
118	    const earliest = buf[0].seq;
119	    // Client is asking for frames older than what we still hold.
120	    if (sinceSeq < earliest - 1) return null;
121	    return buf.filter((f) => f.seq > sinceSeq);
122	  }
123	
124	  /** Earliest retained seq for sessionId, or 1 if no frames yet. */
125	  earliestSeq(sessionId: string): number {
126	    const buf = this.buffers.get(sessionId);
127	    return buf?.[0]?.seq ?? 1;
128	  }
129	}
130	
131	// ---------------------------------------------------------------------------
132	// WsHandlerContext — shared state injected into each connection
133	// ---------------------------------------------------------------------------
134	
135	export interface WsHandlerContext {
136	  db: DbPool;
137	  idempotency: IdempotencyStore;
138	  seqStore: SessionSeqStore;
139	  backfillBuffer: BackfillBuffer;
140	}
141	
142	// ---------------------------------------------------------------------------
143	// Internal helpers
144	// ---------------------------------------------------------------------------
145	
146	function send(socket: WebSocket, frame: ServerFrame): void {
147	  if (socket.readyState === socket.OPEN) {
148	    socket.send(JSON.stringify(frame));
149	  }
150	}
151	
152	/** Read a workflow snapshot from the read-only SQLite connection. */
153	function buildSnapshot(db: DbPool, workflowId: string): WorkflowSnapshotPayload | null {
154	  const reader = db.reader();
155	
156	  const wf = reader
157	    .prepare('SELECT id, name, status, current_stage, created_at, recovery_state FROM workflows WHERE id = ?')
158	    .get(workflowId) as {
159	      id: string;
160	      name: string;
161	      status: string;
162	      current_stage: string | null;
163	      created_at: string;
164	      recovery_state: string | null;
165	    } | undefined;
166	
167	  if (!wf) return null;
168	
169	  // Parse pipeline to get stages.
170	  const pipelineRow = reader
171	    .prepare('SELECT pipeline FROM workflows WHERE id = ?')
172	    .get(workflowId) as { pipeline: string } | undefined;
173	
174	  let stages: StageProjection[] = [];
175	  if (pipelineRow?.pipeline) {
176	    try {
177	      const pipeline = JSON.parse(pipelineRow.pipeline) as {
178	        stages?: Array<{
179	          id: string;
180	          run: 'once' | 'per-item';
181	          phases: string[];
182	          needs_approval?: boolean;
183	        }>;
184	      };
185	      const items = reader
186	        .prepare('SELECT stage_id, status FROM items WHERE workflow_id = ?')
187	        .all(workflowId) as Array<{ stage_id: string; status: string }>;
188	
189	      stages = (pipeline.stages ?? []).map((s) => ({
190	        id: s.id,
191	        run: s.run,
192	        phases: s.phases,
193	        status: computeStageStatus(items, s.id),
194	        needsApproval: s.needs_approval ?? false,
195	      }));
196	    } catch {
197	      // malformed pipeline JSON — return empty stages rather than crashing
198	    }
199	  }
200	
201	  const itemRows = reader
202	    .prepare(
203	      'SELECT id, stage_id, status, current_phase, retry_count, blocked_reason FROM items WHERE workflow_id = ? ORDER BY rowid',
204	    )
205	    .all(workflowId) as Array<{
206	      id: string;
207	      stage_id: string;
208	      status: string;
209	      current_phase: string | null;
210	      retry_count: number;
211	      blocked_reason: string | null;
212	    }>;
213	
214	  const items: ItemProjection[] = itemRows.map((i) => ({
215	    id: i.id,
216	    stageId: i.stage_id,
217	    state: {
218	      status: i.status,
219	      currentPhase: i.current_phase,
220	      retryCount: i.retry_count,
221	      blockedReason: i.blocked_reason,
222	    },
223	    displayTitle: null,
224	    displaySubtitle: null,
225	  }));
226	
227	  const sessionRows = reader
228	    .prepare(
229	      'SELECT id, phase, started_at, parent_session_id FROM sessions WHERE workflow_id = ? AND ended_at IS NULL ORDER BY started_at',
230	    )
231	    .all(workflowId) as Array<{
232	      id: string;
233	      phase: string;
234	      started_at: string;
235	      parent_session_id: string | null;
236	    }>;
237	
238	  const activeSessions: SessionProjection[] = sessionRows.map((s) => ({
239	    sessionId: s.id,
240	    phase: s.phase,
241	    attempt: 0, // TODO: compute from events table when pipeline engine is integrated
242	    startedAt: s.started_at,
243	    parentSessionId: s.parent_session_id,
244	  }));
245	
246	  const attentionRows = reader
247	    .prepare(
248	      'SELECT id, kind, payload, created_at FROM pending_attention WHERE workflow_id = ? AND acknowledged_at IS NULL ORDER BY created_at',
249	    )
250	    .all(workflowId) as Array<{
251	      id: number;
252	      kind: string;
253	      payload: string;
254	      created_at: string;
255	    }>;
256	
257	  const pendingAttention: PendingAttentionEntry[] = attentionRows.map((a) => ({
258	    id: a.id,
259	    kind: a.kind,
260	    payload: (() => {
261	      try {
262	        return JSON.parse(a.payload);
263	      } catch {
264	        return a.payload;
265	      }
266	    })(),
267	    createdAt: a.created_at,
268	  }));
269	
270	  return {
271	    workflow: {
272	      id: wf.id,
273	      name: wf.name,
274	      status: wf.status,
275	      currentStage: wf.current_stage,
276	      createdAt: wf.created_at,
277	      recoveryState: wf.recovery_state ? JSON.parse(wf.recovery_state) : null,
278	      githubState: null,
279	    },
280	    stages,
281	    items,
282	    activeSessions,
283	    pendingAttention,
284	  };
285	}
286	
287	/** Derive stage status from item rows for that stage. */
288	function computeStageStatus(
289	  items: Array<{ stage_id: string; status: string }>,
290	  stageId: string,
291	): StageProjection['status'] {
292	  const stageItems = items.filter((i) => i.stage_id === stageId);
293	  if (stageItems.length === 0) return 'pending';
294	  const statuses = new Set(stageItems.map((i) => i.status));
295	  if (statuses.has('in_progress') || statuses.has('bootstrapping')) return 'in_progress';
296	  if (
297	    stageItems.every((i) =>
298	      ['complete', 'blocked', 'abandoned'].includes(i.status),
299	    )
300	  ) {
301	    return stageItems.some((i) => i.status === 'blocked') ? 'blocked' : 'complete';
302	  }
303	  if (statuses.has('awaiting_user') || statuses.has('awaiting_retry')) return 'in_progress';
304	  return 'pending';
305	}
306	
307	// ---------------------------------------------------------------------------
308	// Per-connection handlers
309	// ---------------------------------------------------------------------------
310	
311	function handleSubscribe(
312	  socket: WebSocket,
313	  frame: ClientFrame<SubscribePayload>,
314	  subscriptions: Map<string, boolean>,
315	  ctx: WsHandlerContext,
316	): void {
317	  const { workflowId, sinceSeq } = frame.payload;
318	
319	  // Enforce subscription cap (AC-3).
